text:
Hello Patrick,

>>Can you try this following patch on your system?
>>This resolves it on my test VM.

Thank you very much! This patch (plus previous patch) works fine for me.
Successfully tested for amd64 CURRENT r313132 with enabled VIMAGE and TCP_RFC7413 kernel options.

Index: sys/netinet/tcp_subr.c
===================================================================
--- sys/netinet/tcp_subr.c      (revision 313106)
+++ sys/netinet/tcp_subr.c      (working copy)
@@ -679,6 +679,10 @@
        V_sack_hole_zone = uma_zcreate("sackhole", sizeof(struct sackhole),
            NULL, NULL, NULL, NULL, UMA_ALIGN_PTR, 0);

+#ifdef TCP_RFC7413
+       tcp_fastopen_init();
+#endif
+
        /* Skip initialization of globals for non-default instances. */
        if (!IS_DEFAULT_VNET(curvnet))
                return;
@@ -732,10 +736,6 @@
 #ifdef TCPPCAP
        tcp_pcap_init();
 #endif
-
-#ifdef TCP_RFC7413
-       tcp_fastopen_init();
-#endif
 }

 #ifdef VIMAGE

Index: sys/netinet/tcp_fastopen.c
===================================================================
--- sys/netinet/tcp_fastopen.c  (revision 313106)
+++ sys/netinet/tcp_fastopen.c  (working copy)
@@ -209,6 +209,7 @@
        rm_init(&V_tcp_fastopen_keylock, "tfo_keylock");
        callout_init_rm(&V_tcp_fastopen_autokey_ctx.c,
            &V_tcp_fastopen_keylock, 0);
+       V_tcp_fastopen_autokey_ctx.v = curvnet;
        V_tcp_fastopen_keys.newest = TCP_FASTOPEN_MAX_KEYS - 1;
 }
